#include <qpdf/QUtil.hh>
#include <qpdf/rijndael.h>
#include <cstring>
#include <stdexcept>
#include <stdlib.h>
#include <string>

AES_PDF_native::AES_PDF_native(
    bool encrypt,
    unsigned char const* a_key,
    size_t key_bytes,
    bool cbc_mode,
    unsigned char* cbc_block) :
    encrypt(encrypt),
    cbc_mode(cbc_mode),
    cbc_block(cbc_block)
{
    size_t keybits = 8 * key_bytes;
    key = std::make_unique<unsigned char[]>(key_bytes);
    rk = std::make_unique<uint32_t[]>(RKLENGTH(keybits));
    size_t rk_bytes = RKLENGTH(keybits) * sizeof(uint32_t);
    std::memcpy(key.get(), a_key, key_bytes);
    std::memset(rk.get(), 0, rk_bytes);
    if (encrypt) {
        nrounds = rijndaelSetupEncrypt(rk.get(), key.get(), keybits);
    } else {
        nrounds = rijndaelSetupDecrypt(rk.get(), key.get(), keybits);
    }
}

void
AES_PDF_native::update(unsigned char* in_data, unsigned char* out_data)
{
    if (encrypt) {
        if (cbc_mode) {
            for (size_t i = 0; i < QPDFCryptoImpl::rijndael_buf_size; ++i) {
                in_data[i] ^= cbc_block[i];
            }
        }
        rijndaelEncrypt(rk.get(), nrounds, in_data, out_data);
        if (cbc_mode) {
            memcpy(cbc_block, out_data, QPDFCryptoImpl::rijndael_buf_size);
        }
    } else {
        rijndaelDecrypt(rk.get(), nrounds, in_data, out_data);
        if (cbc_mode) {
            for (size_t i = 0; i < QPDFCryptoImpl::rijndael_buf_size; ++i) {
                out_data[i] ^= cbc_block[i];
            }
            memcpy(cbc_block, in_data, QPDFCryptoImpl::rijndael_buf_size);
        }
    }
}

#include <qpdf/BitStream.hh>

#include <qpdf/QIntC.hh>
#include <qpdf/Util.hh>

// See comments in bits_functions.hh
#define BITS_READ 1
#include <qpdf/bits_functions.hh>

using namespace qpdf;

BitStream::BitStream(unsigned char const* p, size_t nbytes) :
    start(p),
    nbytes(nbytes)
{
    reset();
}

void
BitStream::reset()
{
    p = start;
    bit_offset = 7;
    if (QIntC::to_uint(nbytes) > static_cast<unsigned int>(-1) / 8) {
        throw std::runtime_error("array too large for bitstream");
    }
    bits_available = 8 * nbytes;
}

unsigned long long
BitStream::getBits(size_t nbits)
{
    return read_bits(this->p, this->bit_offset, this->bits_available, nbits);
}

long long
BitStream::getBitsSigned(size_t nbits)
{
    unsigned long long bits = read_bits(this->p, this->bit_offset, this->bits_available, nbits);
    long long result = 0;
    if (static_cast<long long>(bits) > 1LL << (nbits - 1)) {
        result = static_cast<long long>(bits - (1ULL << nbits));
    } else {
        result = static_cast<long long>(bits);
    }
    return result;
}

int
BitStream::getBitsInt(size_t nbits)
{
    return static_cast<int>(
        // line-break
        QIntC::to_uint(read_bits(this->p, this->bit_offset, this->bits_available, nbits)));
}

void
BitStream::skipToNextByte()
{
    if (bit_offset != 7) {
        size_t bits_to_skip = bit_offset + 1;
        util::internal_error_if(
            bits_available < bits_to_skip, "overflow skipping to next byte in bitstream");
        bit_offset = 7;
        ++p;
        bits_available -= bits_to_skip;
    }
}

